//
import { $Browser } from '../../../../core/browser-detect';
import { expandableState } from '../../../expandable/expandable-parser';

function StyleElement() {
    let manager = this,
        { options } = manager,
        { markParser, trackerElement, expandableParser } = options,
        expanded = expandableState(markParser),
        { isHorizontal } = markParser._spec, // TODO: work
        //
        addOverFlowY = options.legendInstance.meta.addOverFlowY,
        overflowType = isHorizontal && !addOverFlowY ? 'x' : 'y',
        scrollType = isHorizontal && !addOverFlowY ? 'scrollLeft' : 'scrollTop',
        { html } = expandableParser,
        { target } = markParser._spec,
        _target = target();

    trackerElement.html(html(expanded, true, options.legendInstance.meta.order));

    if (expanded) {
        _target.style(`overflow-${overflowType}`, 'auto');
    } else {
        _target.node()[scrollType] = 0;
        _target.style(`overflow-${overflowType}`, 'hidden');
    }
}

export { StyleElement };
